// Minimal HTML mode for Ace (small subset)
/* global ace */
ace.define('ace/mode/html_highlight_rules', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextHighlightRules = require('ace/mode/text_highlight_rules').TextHighlightRules;

  const HtmlHighlightRules = function () {
    this.$rules = {
      start: [
        { token: 'comment', regex: '<!--.*?-->' },
        { token: 'meta.tag', regex: '<\\/?[a-zA-Z][a-zA-Z0-9:-]*' },
        { token: 'entity.other.attribute-name', regex: '\\s+[a-zA-Z_:][a-zA-Z0-9:._-]*(?=\\=)' },
        { token: 'keyword.operator', regex: '=' },
        { token: 'string', regex: '"(?:\\\\.|[^"\\\\])*"' },
        { token: 'string', regex: "'(?:\\\\.|[^'\\\\])*'" },
        { token: 'meta.tag', regex: '\\/?>' },
        { token: 'text', regex: '[^<]+' },
      ],
    };
  };
  oop.inherits(HtmlHighlightRules, TextHighlightRules);
  exports.HtmlHighlightRules = HtmlHighlightRules;
});

ace.define('ace/mode/html', ['require', 'exports', 'module', 'ace/lib/oop', 'ace/mode/text', 'ace/mode/html_highlight_rules'], function (require, exports, module) {
  const oop = require('ace/lib/oop');
  const TextMode = require('ace/mode/text').Mode;
  const Rules = require('ace/mode/html_highlight_rules').HtmlHighlightRules;

  const Mode = function () {
    this.HighlightRules = Rules;
    this.$behaviour = this.$defaultBehaviour;
  };
  oop.inherits(Mode, TextMode);
  exports.Mode = Mode;
});

